#include <stdio.h>
int main() {
    int T, N, i, j, count, steps;
    int notes[105];
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        for (i = 0; i < N; i++) {
            scanf("%d", &notes[i]);
        }
        count = 1;
        steps = 0;
        for (i = 1; i < N; i++) {
            if (notes[i] != notes[i - 1]) {
                count++;
            }
        }
        for (i = 0; i < N - 1; i++) {
            if (notes[i] != notes[i + 1]) {
                steps++;
            }
        }
        printf("%d\n", steps);
    }
    return 0;
}

