code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] notes = new int[N];
            for (int i = 0; i < N; i++) {
                notes[i] = sc.nextInt();
            }
            int count = 1;
            int steps = 0;
            for (int i = 1; i < N; i++) {
                if (notes[i] != notes[i - 1]) {
                    count++;
                }
            }
            for (int i = 0; i < N - 1; i++) {
                if (notes[i] != notes[i + 1]) {
                    steps++;
                }
            }
            System.out.println(steps);
        }
    }
}

